os.makedirs("data", exist_ok=True)
outfile = "data/labeled_posts.csv"
with open(outfile, "w", newline="", encoding="utf-8") as f:
    writer = csv.DictWriter(f, fieldnames=["text", "label", "source", "notes"])
    writer.writeheader()
    for i, (text, label) in enumerate(POSTS):
        writer.writerow({"text": text, "label": label,
                         "source": f"synthetic:{i}", "notes": ""})

from collections import Counter
dist = Counter(label for _, label in POSTS)
print(f"Generated {len(POSTS)} posts → {outfile}")
for label, count in dist.most_common():
    print(f"  {label}: {count} ({count/len(POSTS)*100:.1f}%)")
print("\nNext: review labels, add notes for 3+ hard cases, then run Colab.")
